Variable.doc:
Middle-click synthesis configuration. Two trigger modes, each with an independently-configurable trigger type:

middleClick = {
  enabled = true,

  multiFinger = {
    enabled     = true,
    fingerCount = 3,            -- >= this many fingers fires middle-click
    trigger     = "either",     -- "tap" | "click" | "either"
    maxAgeMs    = 1500,         -- a touch only counts toward fingerCount if it BEGAN this recently before the click
  },

  topCenter = {
    enabled = true,
    devices = { magicMouse = true, trackpad = true },
    trigger = "either",         -- "tap" | "click" | "either"
    xMin = 0.30, xMax = 0.70,   -- normalized fractions of the
    yMin = 0.00, yMax = 0.30,   -- device surface (0,0 = top-left)
    maxAgeMs = 1500,            -- a touch only counts as a deliberate placement if it ENTERED the region this recently
  },

  tap = {                       -- shared tap-validity thresholds
    maxDurationMs    = 200,
    maxTravelPx      = 12,      -- max cursor travel during the tap
    maxSurfaceTravel = 0.05,    -- max normalized surface travel of any touch in the session
  },
}
